-- 2026-06-01: knee_patellar_tendinopathy — фазы «Путь» + структурированные критерии перехода.
-- Knee protocols, коммит S1 (ТЗ TZ_PATIENT_PATH_KNEE_PROTOCOLS.md §7, по образцу knee_oa).
--
-- Источник: PROTOCOLS досье тендинопатии надколенника/квадрицепса (колено прыгуна)
--   + PROTOCOLS/_ext_knee_patellar_tendinopathy.json.
-- Решение Vadim 2026-06-01: прогрессия КРИТЕРИЙ-ЗАВИСИМАЯ, а не календарная — главный гейт между
-- стадиями = реактивность боли в течение суток на нагрузочном тесте + порог боли ≤3 из 10 +
-- достижение силовых порогов. Поэтому duration_weeks у всех фаз пустой (NULL) намеренно.
-- 5 фаз (нумерация 1..5, фазы 0 в данных нет): 1 Снятие раздражения → 2 Силовая основа →
-- 3 Прыжковые упражнения → 4 Возврат в спорт → 5 Поддержание (бессрочная).
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона/цитат) — Vadim калибрует через AdminContent.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев (ТЗ §2.3): авто-проверяемо сегодня только боль ВАШ с числовым порогом →
-- criterion_type 'measurement' (measurement_type='vas_score' source='pain' — единый код против
-- pain_entries.vas_score, как в ACL-seed 20260518 и knee_oa). Качественное да/нет от пациента
-- (вернулась ли боль к исходной за сутки, полная ли переносимость тренировок) → 'self_report'.
-- Все прочие числовые пороги (сила в % массы тела, симметрия сторон в %, прыжковые тесты,
-- баллы опросника) система не хранит → 'instructor_check' с порогом в тексте label (куратор вводит очно).
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee_oa/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы knee_patellar_tendinopathy (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
