-- =====================================================
-- 2. Структурированные критерии перехода knee_patellar_tendinopathy
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (снятие раздражения → силовая основа)
  (1, 'pain_tolerable_iso',     'Боль на нагрузке снизилась до приемлемого уровня (≤ 3 из 10)',                       'measurement'::varchar, 'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 3::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'pain_returns_24h_p1',    'После пробного приседания на одной ноге боль возвращается к обычному уровню за сутки', 'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'После приседания на одной ноге боль возвращается к обычному уровню в течение суток?', 'Сравните с тем, как болит в покое', 20::smallint, TRUE),
  -- Фаза 2 → Фаза 3 (силовая основа → прыжковые упражнения)
  (2, 'leg_press_strength',     'Хорошая сила ноги: жим одной ногой около 150% веса тела на 4×8 (оценивает куратор)',  'instructor_check',     NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'pain_tolerable_load',    'Боль на нагрузке держится на приемлемом уровне (≤ 3 из 10)',                          'measurement',          'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'pain_returns_24h_p2',    'После пробного приседания на одной ноге боль возвращается к обычному уровню за сутки', 'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'После приседания на одной ноге боль возвращается к обычному уровню в течение суток?', 'Проверка переносимости силовой нагрузки', 30::smallint, TRUE),
  -- Фаза 3 → Фаза 4 (прыжковые упражнения → возврат в спорт)
  (3, 'full_tolerance_p3',      'Тренировки переносятся без обострения (боль возвращается к обычному уровню за сутки)', 'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Прыжковые тренировки переносятся без обострения боли?', 'Боль после прыжков уходит к обычному уровню за сутки', 10::smallint, TRUE),
  (3, 'pain_tolerable_plyo',    'Боль при прыжковых упражнениях держится на приемлемом уровне (≤ 3 из 10)',            'measurement',          'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'strength_symmetry_p3',   'Разница в силе и мощности между ногами устранена (оценивает куратор)',                 'instructor_check',     NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  -- Фаза 4 → Фаза 5 (возврат в спорт → поддержание)
  (4, 'full_tolerance_p4',      'Тренировки переносятся в полном объёме без обострения (боль уходит за сутки)',        'self_report',          NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Полноценные тренировки переносятся без обострения боли?', 'Боль возвращается к обычному уровню в течение суток', 10::smallint, TRUE),
  (4, 'quad_lsi_90',            'Сила бедра больной ноги ≥ 90% от здоровой (оценивает куратор)',                       'instructor_check',     NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (4, 'hop_lsi_90',             'Прыжковые тесты ≥ 90% или вровень со здоровой ногой (оценивает куратор)',             'instructor_check',     NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'leg_press_symmetry',     'Сила в жиме ногами сравнялась со здоровой ногой (оценивает куратор)',                 'instructor_check',     NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, FALSE),
  (4, 'visa_p_near_norm',       'Балл опросника здоровья сухожилия близок к норме (около 80–90, оценивает куратор)',   'instructor_check',     NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 50::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_patellar_tendinopathy' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
